import React from "react";
import "./NutritionInfo.css"; // make sure this line stays!

export default function NutritionInfo() {
  const imgURL = "https://thumbs.dreamstime.com/b/diet-nutrition-26610524.jpg";

  const sections = [
    {
      title: "Healthy Diet & Everyday Nutrition",
      desc: "A balanced diet provides essential nutrients, supports digestion, boosts immunity, and enhances long-term health.",
      img: imgURL,
      reverse: false, // text left, image right
    },
    {
      title: "Importance of Vitamins & Minerals",
      desc: "Micronutrients such as Vitamin A, C, D, Iron, and Calcium are vital for immunity, bone strength, metabolism, and overall energy.",
      img: imgURL,
      reverse: true, // image left, text right
    },
  ];

  return (
    <div className="nutrition-wrapper">
      <h1 className="nutrition-title">Nutrition Information</h1>

      {sections.map((sec, index) => (
        <div
          key={index}
          className={`nutrition-section ${sec.reverse ? "reverse" : ""}`}
        >
          {/* TEXT SIDE */}
          <div className="nutrition-text">
            <h2>{sec.title}</h2>
            <p>{sec.desc}</p>
          </div>

          {/* IMAGE SIDE */}
          <div className="nutrition-image-box">
            <img src={sec.img} alt={sec.title} />
          </div>
        </div>
      ))}
    </div>
  );
}
